define("block_portalmessage/dismiss",["core/ajax","core/notification"],(function(Ajax,Notification){const SELECTORS={DISMISS:'[data-action="dismiss"]'},dismissMessageVersion=messageVersion=>{const request={methodname:"block_portalmessage_dismiss_message",args:{messageversion:messageVersion}};return Ajax.call([request])[0]},registerDismissHandler=root=>{const dismissButton=root.querySelector(SELECTORS.DISMISS);dismissButton&&dismissButton.addEventListener("click",(event=>{event.preventDefault();const messageVersion=parseInt(root.dataset.messageVersion,10);if(!Number.isNaN(messageVersion))return dismissMessageVersion(messageVersion).then((()=>{const blockContainer=root.closest(".block");blockContainer?blockContainer.remove():root.remove();})).catch(Notification.exception)}))};return{init:containerId=>{const root=document.getElementById(containerId);root&&registerDismissHandler(root)}}}));
